import{j as l,b as a,c as e,aa as i}from"./chunks/framework.Bxf40uRC.js";const b=JSON.parse('{"title":"Redis之网络模型","description":"","frontmatter":{},"headers":[],"relativePath":"Redis/Redis之网络模型.md","filePath":"Redis/Redis之网络模型.md","lastUpdated":null}'),t={name:"Redis/Redis之网络模型.md"},o=i('<h1 id="redis之网络模型" tabindex="-1">Redis之网络模型 <a class="header-anchor" href="#redis之网络模型" aria-label="Permalink to &quot;Redis之网络模型&quot;">​</a></h1><p><img src="https://s2.loli.net/2023/12/21/I1NXQDFEPOn8s3K.png" alt="image-20231221151903863"></p><p>Linux系统为了提高IO效率，会在用户空间和内核空间都加入缓冲区</p><ul><li>写数据的时候，要把用户缓冲数据拷贝到内核缓冲区，然后写入设备</li><li>读数据时，要从设备读取数据到缓冲区中，然后拷贝到用户缓冲区</li></ul><p><img src="https://s2.loli.net/2023/12/21/SemyqB9K8Rwdzca.png" alt="image-20231221152121323"></p><h2 id="阻塞io" tabindex="-1">阻塞IO <a class="header-anchor" href="#阻塞io" aria-label="Permalink to &quot;阻塞IO&quot;">​</a></h2><p>顾名思义，阻塞IO就是两个阶段都必须阻塞等待</p><p><img src="https://s2.loli.net/2023/12/21/YQEiWu5IpoFdRtT.png" alt="image-20231221152337829"></p><h2 id="非阻塞io" tabindex="-1">非阻塞IO <a class="header-anchor" href="#非阻塞io" aria-label="Permalink to &quot;非阻塞IO&quot;">​</a></h2><p>顾名思义，非阻塞IO的recvfrom操作会立即返回结果而不是阻塞用户进程。</p><p><img src="https://s2.loli.net/2023/12/21/AkKgp6S9oBZFjVL.png" alt="image-20231221152530303"></p><p>可以看到，非阻塞IO模型中，用户进程在第一个阶段是非阻塞，第二个阶段是阻塞状态。虽然是非阻塞，但是性能并没有得到提高。而忙等机制会导致cpu空转，cpu使用率暴增。</p><h2 id="io多路复用" tabindex="-1">IO多路复用 <a class="header-anchor" href="#io多路复用" aria-label="Permalink to &quot;IO多路复用&quot;">​</a></h2><p>无论是阻塞还是非阻塞IO，用户应用在一阶段都需要调用recvfrom来获取数据，差别在于无数据时的处理方案：</p><ul><li>如果调用recvfrom时，恰好没有数据，阻塞IO会使进程阻塞，非阻塞IO使CPU空转，都不能充分发挥作用。</li><li>如果调用recvfrom时，恰好有数据，则用户进程可以直接进入第二阶段，读取并处理数据。</li></ul><p>比如服务端处理客户端socket请求时，在单线程的情况下，只能依次处理每一个socket，如果正在处理的socket恰好未就绪(数据不可读或者不可写)，线程就会被阻塞，所有其他客户端socket都必须等待，性能自然会很差。</p><h3 id="解决方案" tabindex="-1">解决方案 <a class="header-anchor" href="#解决方案" aria-label="Permalink to &quot;解决方案&quot;">​</a></h3><ol><li>多线程处理</li><li>哪个任务的数据就绪了，就先处理哪个的</li></ol><h3 id="文件描述符" tabindex="-1">文件描述符 <a class="header-anchor" href="#文件描述符" aria-label="Permalink to &quot;文件描述符&quot;">​</a></h3><p>文件描述符(File Descriptor)：简称FD，是一个从0开始递增的无符号整数，用来关联Linux中的一个文件。在linux中，一切皆文件，，例如常规文件，视频，设备等，当然也包括网络套接字。</p><p><strong>IO多路复用</strong>：是利用单个线程同时监听多个FD，并在某个FD可读、可写时得到通知，从而避免无效等待，充分利用cpu资源</p><p><img src="https://s2.loli.net/2023/12/21/ONy1MsQrxELefSl.png" alt="image-20231221154218165"></p><h3 id="io多路复用的监听方式" tabindex="-1">IO多路复用的监听方式 <a class="header-anchor" href="#io多路复用的监听方式" aria-label="Permalink to &quot;IO多路复用的监听方式&quot;">​</a></h3><ul><li>select</li><li>poll</li><li>epoll</li></ul><h3 id="select" tabindex="-1">select <a class="header-anchor" href="#select" aria-label="Permalink to &quot;select&quot;">​</a></h3><p><img src="https://s2.loli.net/2023/12/21/6RIVwxPyNTHijEF.png" alt="image-20231221155128778"></p><h4 id="存在的问题" tabindex="-1">存在的问题 <a class="header-anchor" href="#存在的问题" aria-label="Permalink to &quot;存在的问题&quot;">​</a></h4><ul><li>需要将整个fd_set从用户空间拷贝到内核空间，select结束还要再次拷贝回用户空间，繁琐</li><li>select无法得知具体是哪个fd值，只能遍历，时间复杂度高</li><li>fd_set监听的fd数量不超过1024</li></ul><h4 id="poll" tabindex="-1">POLL <a class="header-anchor" href="#poll" aria-label="Permalink to &quot;POLL&quot;">​</a></h4><p>IO流程</p><ul><li>创建pollfd数组，向其中添加关注的fd信息，数组大小自定义</li><li>调用poll函数，将pollfd数组拷贝到内核空间中，转链表存储，无上限</li><li>内核遍历fd，判断是否就绪</li><li>数据就绪或者超时后，拷贝pollfd数据到用户空间，返回就绪fd数量n</li><li>用户进程判断n是否大于零，然后遍历pollfd数组，找到就绪的fd</li></ul><p><img src="https://s2.loli.net/2023/12/22/gKoFU47NPcrqBad.png" alt="image-20231222024526236"></p><h4 id="存在的问题-1" tabindex="-1">存在的问题 <a class="header-anchor" href="#存在的问题-1" aria-label="Permalink to &quot;存在的问题&quot;">​</a></h4><ul><li>select模式中的fd_set大小固定是1024，而pollfd在内核中采用链表，理论无上限</li><li>监听fd越多，每次遍历消耗时间也越久，性能反而会下降</li></ul><h3 id="epoll" tabindex="-1">epoll <a class="header-anchor" href="#epoll" aria-label="Permalink to &quot;epoll&quot;">​</a></h3><p>epoll模式是对select和poll的改进，它提供三个函数:</p><p><img src="https://s2.loli.net/2023/12/22/iGNWbTsBjEQ3cXl.png" alt="image-20231222023734241"></p><h4 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to &quot;优势&quot;">​</a></h4><ul><li>基于红黑树保存要监听的FD，理论上是没有上限，而且增删改查的效率都很高，性能不会随着监听的FD数量增多而下降；</li><li>内核会将就绪的FD直接拷贝到用户空间的指定位置，用户进程无需遍历所有的FD就能知道FD是谁；</li></ul><h4 id="事件通知机制" tabindex="-1">事件通知机制 <a class="header-anchor" href="#事件通知机制" aria-label="Permalink to &quot;事件通知机制&quot;">​</a></h4><p>当FD有数据可读时，我们调用epoll_wait就可以得到通知。但是事件通知的模式有两种:</p><ul><li>LevelTriggered：简称LT。当FD有数据可读时，会重复通知多次，直到数据处理完成。是Epoll的默认模式 <ul><li>重复通知，效率存在问题</li><li>多线程存在竞争问题</li></ul></li><li>EdgeTriggered：简称ET。当FD有数据可读时，只会被通知一次，不管数据是否处理完成。 <ul><li>容易造成数据没读完，FD就被删除了</li><li>结合非阻塞IO，效率会更好一点</li></ul></li></ul><p>举个例子:</p><ol><li>假设一个客户端socket对应的FD已经注册到了epoll实例中</li><li>客户端socket发送了2kb的数据</li><li>服务端调用epoll_wait，得到通知说FD就绪</li><li>服务端从FD读取了1kb数据</li><li>回到步骤3(再次调用epoll_wait，形成循环)</li></ol><h4 id="web服务流程" tabindex="-1">web服务流程 <a class="header-anchor" href="#web服务流程" aria-label="Permalink to &quot;web服务流程&quot;">​</a></h4><p>基于epoll模式的web服务的基本流程如图:</p><p><img src="https://s2.loli.net/2023/12/23/ZRF5QPj2pctnhAu.png" alt="image-20231223142151914"></p><h2 id="信号驱动io" tabindex="-1">信号驱动IO <a class="header-anchor" href="#信号驱动io" aria-label="Permalink to &quot;信号驱动IO&quot;">​</a></h2><p><strong>信号驱动IO</strong>是与内核简历SIGIO信号关联并设置回调，当内核有FD就绪的时，就会发送SIGIO信号通知用户，期间用户以执行其他业务，无需阻塞等待。</p><p><img src="https://s2.loli.net/2023/12/23/EFxIz98sMplJbOh.png" alt="image-20231223143031766"></p><h3 id="缺点" tabindex="-1">缺点 <a class="header-anchor" href="#缺点" aria-label="Permalink to &quot;缺点&quot;">​</a></h3><ul><li>当有大量IO操作的时，信号较多，SIGIO处理函数不能及时处理可能导致信号队列溢出</li><li>当内核空间与用户空间的频繁信号交互，性能比较低</li></ul><h3 id="异步io" tabindex="-1">异步IO <a class="header-anchor" href="#异步io" aria-label="Permalink to &quot;异步IO&quot;">​</a></h3><p>异步IO的整个过程都是非阻塞的，用户进程调用完异步API后就可以去做其他事情，内核等待数据就绪并拷贝到用户空间才会递交信号，通知用户进程。</p><p><img src="https://s2.loli.net/2023/12/23/2q4YDPjpVE9az6v.png" alt="image-20231223144418499"></p><p>可以看到异步IO的两个过程都是非阻塞的</p><h3 id="同步和异步" tabindex="-1">同步和异步 <a class="header-anchor" href="#同步和异步" aria-label="Permalink to &quot;同步和异步&quot;">​</a></h3><p>IO操作是同步还是异步的，关键看数据在内核空间与用户空间的拷贝过程(数据读写的IO操作)，也就是阶段二是同步还是异步:</p><p><img src="https://s2.loli.net/2023/12/23/J57jzBW3qQFMfae.png" alt="image-20231223144546593"></p><h3 id="redis网络模型" tabindex="-1">Redis网络模型 <a class="header-anchor" href="#redis网络模型" aria-label="Permalink to &quot;Redis网络模型&quot;">​</a></h3><h4 id="redis到底是单线程还是多线程" tabindex="-1">Redis到底是单线程还是多线程？ <a class="header-anchor" href="#redis到底是单线程还是多线程" aria-label="Permalink to &quot;Redis到底是单线程还是多线程？&quot;">​</a></h4><ul><li>如果仅仅聊Redis的核心业务部分(命令处理)，答案是单线程</li><li>如果是聊整个Redis，那么答案是多线程</li></ul><p>在Redis版本迭代的过程中，在两个重要的时间节点上引入了多线程的支持:</p><ul><li>Redis v4.0：引入多线程异步处理一些耗时比较长的任务，例如异步删除命令unlink</li><li>Redis v6.0：在核心网络模型中引入多线程，进一步提高对于多核CPU的利用率</li></ul><h4 id="为什么redis要选择单线程" tabindex="-1">为什么Redis要选择单线程？ <a class="header-anchor" href="#为什么redis要选择单线程" aria-label="Permalink to &quot;为什么Redis要选择单线程？&quot;">​</a></h4><ul><li>抛开持久化不谈，<strong>Redis是纯内存操作，执行速度非常快，它的性能瓶颈是网络延迟而不是执行速度</strong>，因此多线程并不会带来巨大的性能提升。</li><li>多线程会导致过多的上下文切换，带来不必要的开销</li><li>引入多线程会面临线程安全问题，必然要引入线程锁这样的安全手段，实现复杂度增高，而且性能会大打折扣</li></ul>',66),r=[o];function s(d,h,p,n,c,u){return a(),e("div",null,r)}const f=l(t,[["render",s]]);export{b as __pageData,f as default};
